import React, { useState, useEffect } from "react";
import axios from "axios";
import { Bar } from "react-chartjs-2";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend,
} from "chart.js";

ChartJS.register(CategoryScale, LinearScale, BarElement, Title, Tooltip, Legend);

export default function Reportes() {
  const [ventasPorDia, setVentasPorDia] = useState([]);
  const [ventasPorMes, setVentasPorMes] = useState([]);

  useEffect(() => {
    obtenerReportes();
  }, []);

  const obtenerReportes = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/reportes/ventas");
      setVentasPorDia(res.data.ventasPorDia);
      setVentasPorMes(res.data.ventasPorMes);
    } catch (error) {
      console.error("❌ Error al obtener reportes:", error);
    }
  };

  const dataDias = {
    labels: ventasPorDia.map((v) => v.Fecha),
    datasets: [
      {
        label: "Ventas por día",
        data: ventasPorDia.map((v) => v.Total),
        backgroundColor: "rgba(75, 192, 192, 0.7)",
      },
    ],
  };

  const dataMeses = {
    labels: ventasPorMes.map((v) => v.Mes),
    datasets: [
      {
        label: "Ventas por mes",
        data: ventasPorMes.map((v) => v.Total),
        backgroundColor: "rgba(153, 102, 255, 0.7)",
      },
    ],
  };

  return (
    <div className="container mt-5">
      <h2 className="mb-4">📊 Reportes de Ventas</h2>

      <div className="mb-5">
        <h4>Ventas por Día</h4>
        <Bar data={dataDias} options={{ responsive: true, plugins: { legend: { position: "top" } } }} />
      </div>

      <div className="mb-5">
        <h4>Ventas por Mes</h4>
        <Bar data={dataMeses} options={{ responsive: true, plugins: { legend: { position: "top" } } }} />
      </div>
    </div>
  );
}
